#!/usr/bin/env node
/**
 * F4.4 — Coverage Gate
 *
 * Reads coverage/coverage-summary.json (generated by Vitest's json-summary reporter)
 * and fails if coverage has dropped below the stored minimum.
 *
 * Usage: node scripts/check-coverage-gate.mjs
 * Run after: npx vitest run --coverage
 *
 * The minimum threshold is stored in scripts/coverage-gate-min.json.
 * To update the minimum after improving coverage:
 *   node scripts/check-coverage-gate.mjs --update
 */

import { readFileSync, writeFileSync, existsSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = resolve(__dirname, '..')
const SUMMARY_PATH = resolve(ROOT, 'coverage/coverage-summary.json')
const MIN_PATH = resolve(__dirname, 'coverage-gate-min.json')

/** Conservative floor — always blocks catastrophic regressions. */
const ABSOLUTE_FLOOR = { lines: 50, statements: 50, functions: 50, branches: 35 }

const shouldUpdate = process.argv.includes('--update')

// ── Read current coverage ────────────────────────────────────────────────────

let summary
try {
  summary = JSON.parse(readFileSync(SUMMARY_PATH, 'utf8'))
} catch {
  console.error('❌  coverage/coverage-summary.json not found.')
  console.error('    Run: npx vitest run --coverage')
  process.exit(1)
}

const { total } = summary
if (!total) {
  console.error('❌  Unexpected coverage-summary.json format (no "total" key).')
  process.exit(1)
}

const current = {
  lines: Math.round((total.lines?.pct ?? 0) * 10) / 10,
  statements: Math.round((total.statements?.pct ?? 0) * 10) / 10,
  functions: Math.round((total.functions?.pct ?? 0) * 10) / 10,
  branches: Math.round((total.branches?.pct ?? 0) * 10) / 10,
}

console.log('📊  Current coverage:')
console.log(`    Lines:      ${current.lines}%`)
console.log(`    Statements: ${current.statements}%`)
console.log(`    Functions:  ${current.functions}%`)
console.log(`    Branches:   ${current.branches}%`)

// ── Load stored minimum ──────────────────────────────────────────────────────

let minimum = ABSOLUTE_FLOOR
if (existsSync(MIN_PATH)) {
  try {
    minimum = { ...ABSOLUTE_FLOOR, ...JSON.parse(readFileSync(MIN_PATH, 'utf8')) }
  } catch {
    console.warn('⚠️   Could not read coverage-gate-min.json — using absolute floor.')
  }
}

console.log(`\n🔒  Minimum required:`)
console.log(`    Lines:      ${minimum.lines}%`)
console.log(`    Statements: ${minimum.statements}%`)
console.log(`    Functions:  ${minimum.functions}%`)
console.log(`    Branches:   ${minimum.branches}%\n`)

// ── Check thresholds ─────────────────────────────────────────────────────────

let failed = false
for (const key of ['lines', 'statements', 'functions', 'branches']) {
  if (current[key] < minimum[key]) {
    console.error(`❌  ${key}: ${current[key]}% < required ${minimum[key]}%  (DROPPED ${(minimum[key] - current[key]).toFixed(1)}%)`)
    failed = true
  }
}

if (failed) {
  console.error('\n🚨  Coverage gate failed — merge blocked.')
  process.exit(1)
}

console.log('✅  Coverage gate passed.')

// ── Optionally update stored minimum ─────────────────────────────────────────

if (shouldUpdate) {
  const newMin = {
    lines: Math.max(minimum.lines, current.lines),
    statements: Math.max(minimum.statements, current.statements),
    functions: Math.max(minimum.functions, current.functions),
    branches: Math.max(minimum.branches, current.branches),
  }
  writeFileSync(MIN_PATH, JSON.stringify(newMin, null, 2) + '\n')
  console.log(`\n📝  Stored new minimum: ${JSON.stringify(newMin)}`)
}
